import { useState, useRef, useEffect } from 'react';
import { X, Plus, Trash2, PenLine, RotateCcw } from 'lucide-react';

// ── 도장 이미지 (base64) ──────────────────────────────────
const STAMP_JEONGYUN = "data:image/png;base64,";
const STAMP_GEONHEE  = "data:image/png;base64,";

interface HeadcountData {
    elemM: number; elemF: number;
    midM: number;  midF: number;
    highM: number; highF: number;
    u24M: number;  u24F: number;
}

interface ActivityData {
    activityContent: string;
    suggestion: string;
    headcount: HeadcountData;
    participants: string[];
    signature: string; // base64 서명 이미지
}

interface ActivityModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (data: ActivityData) => void;
    isLoading: boolean;
    roomName: string;
    dateStr: string;
    timeStr: string;
}

const HEADCOUNT_ROWS = [
    { label: '초등', mKey: 'elemM', fKey: 'elemF' },
    { label: '중등', mKey: 'midM',  fKey: 'midF'  },
    { label: '고등', mKey: 'highM', fKey: 'highF' },
    { label: '24세이하', mKey: 'u24M', fKey: 'u24F' },
] as const;

const EMPTY_HEADCOUNT: HeadcountData = {
    elemM:0, elemF:0, midM:0, midF:0, highM:0, highF:0, u24M:0, u24F:0,
};

// ── 서명 패드 컴포넌트 ────────────────────────────────────
function SignaturePad({ onSave }: { onSave: (dataUrl: string) => void }) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const drawing   = useRef(false);
    const [signed, setSigned] = useState(false);
    const [saved,  setSaved]  = useState(false);

    const getPos = (e: MouseEvent | TouchEvent, canvas: HTMLCanvasElement) => {
        const rect = canvas.getBoundingClientRect();
        const scaleX = canvas.width  / rect.width;
        const scaleY = canvas.height / rect.height;
        if (e instanceof TouchEvent) {
            return {
                x: (e.touches[0].clientX - rect.left) * scaleX,
                y: (e.touches[0].clientY - rect.top)  * scaleY,
            };
        }
        return {
            x: (e.clientX - rect.left) * scaleX,
            y: (e.clientY - rect.top)  * scaleY,
        };
    };

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d')!;
        ctx.strokeStyle = '#1E3A8A';
        ctx.lineWidth   = 2.5;
        ctx.lineCap     = 'round';
        ctx.lineJoin    = 'round';

        const start = (e: MouseEvent | TouchEvent) => {
            e.preventDefault();
            drawing.current = true;
            const p = getPos(e, canvas);
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
        };
        const move = (e: MouseEvent | TouchEvent) => {
            e.preventDefault();
            if (!drawing.current) return;
            const p = getPos(e, canvas);
            ctx.lineTo(p.x, p.y);
            ctx.stroke();
            setSigned(true);
        };
        // 🔄 Auto-save on pen/finger lift
        const endWithCheck = () => {
            drawing.current = false;
            if (canvas) {
                // Check if canvas has any drawn content by sampling a pixel
                const ctx2 = canvas.getContext('2d');
                if (!ctx2) return;
                const imageData = ctx2.getImageData(0, 0, canvas.width, canvas.height);
                const hasContent = imageData.data.some((v, i) => i % 4 === 3 && v > 0);
                if (hasContent) {
                    onSave(canvas.toDataURL('image/png'));
                    setSigned(true);
                    setSaved(true);
                }
            }
        };

        canvas.addEventListener('mousedown', start);
        canvas.addEventListener('mousemove', move);
        canvas.addEventListener('mouseup', endWithCheck);
        canvas.addEventListener('touchstart', start, { passive: false });
        canvas.addEventListener('touchmove', move,  { passive: false });
        canvas.addEventListener('touchend', endWithCheck);

        return () => {
            canvas.removeEventListener('mousedown', start);
            canvas.removeEventListener('mousemove', move);
            canvas.removeEventListener('mouseup', endWithCheck);
            canvas.removeEventListener('touchstart', start);
            canvas.removeEventListener('touchmove', move);
            canvas.removeEventListener('touchend', endWithCheck);
        };
    }, [onSave]);

    const clear = () => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d')!;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        setSigned(false);
        setSaved(false);
    };

    return (
        <div>
            <div style={{ border: `1px dashed ${saved ? '#86efac' : '#ccc'}`, borderRadius: 8, background: saved ? '#f0fdf4' : '#fafafa', position: 'relative', transition: 'all 0.3s' }}>
                <canvas ref={canvasRef} width={400} height={120}
                    style={{ width: '100%', height: 120, display: 'block', borderRadius: 8, cursor: 'crosshair', touchAction: 'none' }} />
                {!signed && (
                    <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', pointerEvents: 'none' }}>
                        <span style={{ fontSize: 13, color: '#bbb' }}>여기에 서명해주세요 (그리면 자동 저장됩니다)</span>
                    </div>
                )}
                {saved && (
                    <div style={{ position: 'absolute', top: 6, right: 8, fontSize: 11, color: '#16a34a', fontWeight: 600, pointerEvents: 'none' }}>
                        ✅ 저장됨
                    </div>
                )}
            </div>
            <div style={{ display: 'flex', gap: 8, marginTop: 8 }}>
                <button type="button" onClick={clear}
                    style={{ flex: 1, padding: '8px', border: '1px solid #e5e7eb', borderRadius: 8, fontSize: 13, background: '#fff', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4 }}>
                    <RotateCcw size={14}/> 다시 서명하기
                </button>
            </div>
        </div>
    );
}


// ── PDF 인쇄 컴포넌트 ─────────────────────────────────────
export function printActivityLog(data: {
    roomName: string;
    dateStr: string;
    timeStr: string;
    userName: string;
    activityContent: string;
    suggestion: string;
    headcount: HeadcountData;
    participants: string[];
    signature: string;
    today: string;
}) {
    const totalCount = Object.values(data.headcount).reduce((s,v)=>s+v,0);
    const rows = [
        { label: '초등', m: data.headcount.elemM, f: data.headcount.elemF },
        { label: '중등', m: data.headcount.midM,  f: data.headcount.midF  },
        { label: '고등', m: data.headcount.highM, f: data.headcount.highF },
        { label: '24세이하', m: data.headcount.u24M, f: data.headcount.u24F },
    ];

    const participantCells = [];
    for (let i = 0; i < Math.max(data.participants.length, 6); i += 2) {
        const a = data.participants[i]   || '';
        const b = data.participants[i+1] || '';
        participantCells.push(`
            <tr>
                <td style="border:0.5px solid #999;padding:5px 8px;text-align:center;color:#666;font-size:11px;">${i+1}</td>
                <td style="border:0.5px solid #999;padding:5px 8px;">${a}</td>
                <td style="border:0.5px solid #999;padding:5px 8px;text-align:center;color:#666;font-size:11px;">${i+2}</td>
                <td style="border:0.5px solid #999;padding:5px 8px;">${b}</td>
            </tr>
        `);
    }

    const html = `<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<style>
  @page { size: A4; margin: 15mm 15mm 15mm 15mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Malgun Gothic', sans-serif; font-size: 13px; color: #111; }
  h1 { font-size: 22px; font-weight: bold; text-align: center; margin-bottom: 4px; }
  h2 { font-size: 16px; font-weight: bold; text-align: center; margin-bottom: 16px; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 10px; }
  td, th { border: 0.5px solid #999; padding: 6px 10px; }
  .label { background: #f3f3f3; color: #444; font-weight: bold; width: 80px; }
  .center { text-align: center; }
  .stamp { width: 64px; height: 64px; object-fit: contain; }
  .sig { width: 120px; height: 44px; object-fit: contain; }
  .approval { display: flex; justify-content: flex-end; margin-bottom: 16px; }
  .approval-table td { text-align: center; font-size: 11px; padding: 4px 16px; }
  .approval-img-cell { height: 72px; position: relative; }
  .footer { margin-top: 8px; display: flex; justify-content: space-between; font-size: 11px; color: #666; }
  .auto-note { margin-top: 8px; padding: 6px 10px; background: #eff6ff; border: 0.5px solid #bfdbfe; border-radius: 4px; font-size: 11px; color: #1d4ed8; }
</style>
</head>
<body>
  <h1>창동청소년센터</h1>
  <h2>동아리 활동일지</h2>

  <!-- 결재란 -->
  <div class="approval">
    <table class="approval-table" style="width:auto;">
      <tr>
        <td>담 당</td>
        <td>팀 장</td>
      </tr>
      <tr>
        <td class="approval-img-cell" style="position:relative;">
          <img src="${STAMP_JEONGYUN}" class="stamp"/>
        </td>
        <td class="approval-img-cell">
          <img src="${STAMP_GEONHEE}" class="stamp"/>
        </td>
      </tr>
    </table>
  </div>

  <!-- 기본 정보 -->
  <table>
    <tr>
      <td class="label">동아리명</td>
      <td style="font-weight:bold;">${data.userName}</td>
      <td class="label" style="width:60px;">장 소</td>
      <td>${data.roomName}</td>
    </tr>
    <tr>
      <td class="label">일 시</td>
      <td colspan="3">${data.dateStr} &nbsp; ${data.timeStr}</td>
    </tr>
  </table>

  <!-- 주요활동 -->
  <table>
    <tr>
      <td class="label" style="vertical-align:top;">주요활동</td>
      <td style="line-height:1.8;">${data.activityContent || '(입력 없음)'}</td>
    </tr>
    <tr>
      <td class="label" style="vertical-align:top;">건의사항</td>
      <td>${data.suggestion || '(없음)'}</td>
    </tr>
  </table>

  <!-- 인원 -->
  <table>
    <tr>
      <td class="label center" rowspan="3" style="vertical-align:middle;">인 원<br>(명)</td>
      <td class="label center" style="font-size:11px;">구분</td>
      ${rows.map(r=>`<td class="label center" style="font-size:11px;">${r.label}</td>`).join('')}
      <td class="label center" style="font-size:11px;">일일총계</td>
    </tr>
    <tr>
      <td class="label center" style="font-size:11px;">남</td>
      ${rows.map(r=>`<td class="center">${r.m}</td>`).join('')}
      <td class="center" rowspan="2" style="font-size:18px;font-weight:bold;vertical-align:middle;">${totalCount}명</td>
    </tr>
    <tr>
      <td class="label center" style="font-size:11px;">여</td>
      ${rows.map(r=>`<td class="center">${r.f}</td>`).join('')}
    </tr>
  </table>

  <!-- 참여인원 -->
  <table>
    <tr>
      <td class="label center" rowspan="${participantCells.length+1}" style="vertical-align:middle;width:60px;">참여<br>인원</td>
      <td class="label center" style="font-size:11px;width:30px;">번호</td>
      <td class="label" style="font-size:11px;">이름</td>
      <td class="label center" style="font-size:11px;width:30px;">번호</td>
      <td class="label" style="font-size:11px;">이름</td>
    </tr>
    ${participantCells.join('')}
  </table>

  <!-- 대표자 서명 -->
  <table>
    <tr>
      <td class="label" style="width:80px;vertical-align:middle;">대표자 서명</td>
      <td style="padding:4px 10px;">
        ${data.signature
            ? `<img src="${data.signature}" class="sig"/>`
            : '<span style="color:#bbb;font-size:12px;">(서명 없음)</span>'
        }
      </td>
      <td class="label" style="width:80px;">기록일</td>
      <td>${data.today}</td>
    </tr>
  </table>

  <div class="footer">
    <span>기록자: ${data.participants[0] || data.userName}</span>
    <span>출력일: ${data.today}</span>
  </div>
  <div class="auto-note">이 문서는 창동청소년센터 대관 예약 시스템에서 자동 생성되었습니다.</div>

  <script>window.onload = () => window.print();</script>
</body>
</html>`;

    const win = window.open('', '_blank');
    if (!win) return;
    win.document.write(html);
    win.document.close();
}

// ── 메인 모달 ────────────────────────────────────────────
export function ActivityModal({
    isOpen, onClose, onSubmit, isLoading, roomName, dateStr, timeStr
}: ActivityModalProps) {
    const [activityContent, setActivityContent] = useState('');
    const [suggestion, setSuggestion]           = useState('');
    const [headcount, setHeadcount]             = useState<HeadcountData>(EMPTY_HEADCOUNT);
    const [participants, setParticipants]       = useState<string[]>(['']);
    const [signature, setSignature]             = useState('');
    const [showSigPad, setShowSigPad]           = useState(false);

    if (!isOpen) return null;

    const totalCount = Object.values(headcount).reduce((s,v)=>s+v,0);

    const handleHeadcount = (key: keyof HeadcountData, value: string) =>
        setHeadcount(prev => ({ ...prev, [key]: Math.max(0, parseInt(value)||0) }));
    const addParticipant    = () => setParticipants(prev => [...prev, '']);
    const updateParticipant = (i: number, v: string) => setParticipants(prev => prev.map((p,j) => j===i ? v : p));
    const removeParticipant = (i: number) => {
        if (participants.length === 1) { setParticipants(['']); return; }
        setParticipants(prev => prev.filter((_,j) => j!==i));
    };

    const handleSubmit = () => {
        if (activityContent.trim().length < 15) {
            alert('주요 활동 내용은 최소 15자 이상 필수로 작성해야 합니다.');
            return;
        }

        const filtered = participants.filter(p => p.trim() !== '');
        const nameRegex = /^[가-힣a-zA-Z\s]{2,10}$/;
        for (const p of filtered) {
            if (!nameRegex.test(p)) {
                alert(`참여자 이름('${p}') 형식이 올바르지 않습니다. (초성/특수문자 금지, 2~10자)`);
                return;
            }
        }

        onSubmit({ activityContent, suggestion, headcount, participants: filtered, signature });
        setActivityContent(''); setSuggestion(''); setHeadcount(EMPTY_HEADCOUNT);
        setParticipants(['']); setSignature(''); setShowSigPad(false);
    };

    const td = { border: '0.5px solid #e5e7eb', padding: '6px 8px' };
    const labelTd = { ...td, background: '#f9fafb', color: '#6b7280', fontWeight: 500 as const, fontSize: 12 };
    const inputCls = 'w-full border border-gray-200 rounded-xl p-3 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-brand-400';

    return (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:50, padding:16 }}>
            <div style={{ background:'#fff', borderRadius:16, boxShadow:'0 25px 50px rgba(0,0,0,0.15)', width:'100%', maxWidth:480, maxHeight:'90vh', overflowY:'auto' }}>

                {/* 헤더 */}
                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'16px 20px', borderBottom:'0.5px solid #e5e7eb', position:'sticky', top:0, background:'#fff', zIndex:10 }}>
                    <div>
                        <p style={{ fontWeight:700, fontSize:16, margin:0, color:'#111' }}>예약 신청 + 활동일지</p>
                        <p style={{ fontSize:12, color:'#9ca3af', margin:0 }}>{roomName} · {dateStr} · {timeStr}</p>
                    </div>
                    <button onClick={onClose} style={{ padding:6, borderRadius:'50%', border:'none', background:'#f3f4f6', cursor:'pointer' }}>
                        <X size={16} color="#6b7280"/>
                    </button>
                </div>

                <div style={{ padding:20, display:'flex', flexDirection:'column', gap:20 }}>

                    {/* 주요 활동 */}
                    <div>
                        <label style={{ fontSize:13, fontWeight:600, color:'#374151', display:'block', marginBottom:6 }}>
                            주요 활동 내용 <span style={{ color:'#ef4444', fontWeight:600 }}>(필수, 15자 이상)</span>
                        </label>
                        <textarea value={activityContent} onChange={e=>setActivityContent(e.target.value)}
                            placeholder="활동 내용을 간단히 입력해주세요" rows={3} className={inputCls}/>
                    </div>

                    {/* 인원 */}
                    <div>
                        <label style={{ fontSize:13, fontWeight:600, color:'#374151', display:'block', marginBottom:8 }}>
                            참여 인원 <span style={{ color:'#9ca3af', fontWeight:400 }}>(선택)</span>
                            {totalCount > 0 && <span style={{ marginLeft:8, color:'#1E3A8A', fontWeight:700 }}>총 {totalCount}명</span>}
                        </label>
                        <table style={{ width:'100%', borderCollapse:'collapse', fontSize:13 }}>
                            <thead>
                                <tr>
                                    <td style={labelTd}>구분</td>
                                    <td style={{ ...labelTd, textAlign:'center' }}>초등</td>
                                    <td style={{ ...labelTd, textAlign:'center' }}>중등</td>
                                    <td style={{ ...labelTd, textAlign:'center' }}>고등</td>
                                    <td style={{ ...labelTd, textAlign:'center' }}>24세이하</td>
                                </tr>
                            </thead>
                            <tbody>
                                {(['남','여'] as const).map(sex => (
                                    <tr key={sex}>
                                        <td style={labelTd}>{sex}</td>
                                        {HEADCOUNT_ROWS.map(row => {
                                            const k = (sex==='남' ? row.mKey : row.fKey) as keyof HeadcountData;
                                            return (
                                                <td key={k} style={td}>
                                                    <input type="number" min={0} value={headcount[k]||''} onChange={e=>handleHeadcount(k,e.target.value)}
                                                        placeholder="0" style={{ width:'100%', textAlign:'center', border:'none', outline:'none', background:'transparent', fontSize:13 }}/>
                                                </td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    {/* 참여자 이름 */}
                    <div>
                        <label style={{ fontSize:13, fontWeight:600, color:'#374151', display:'block', marginBottom:8 }}>
                            참여자 이름 <span style={{ color:'#9ca3af', fontWeight:400 }}>(선택)</span>
                        </label>
                        <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
                            {participants.map((name,i) => (
                                <div key={i} style={{ display:'flex', alignItems:'center', gap:8 }}>
                                    <span style={{ fontSize:12, color:'#9ca3af', width:20, textAlign:'right' }}>{i+1}.</span>
                                    <input type="text" value={name} onChange={e=>updateParticipant(i,e.target.value)} placeholder="이름 입력"
                                        style={{ flex:1, border:'1px solid #e5e7eb', borderRadius:8, padding:'8px 12px', fontSize:13, outline:'none' }}/>
                                    <button type="button" onClick={()=>removeParticipant(i)}
                                        style={{ padding:6, border:'none', borderRadius:8, background:'#fff5f5', color:'#ef4444', cursor:'pointer' }}>
                                        <Trash2 size={14}/>
                                    </button>
                                </div>
                            ))}
                        </div>
                        <button type="button" onClick={addParticipant}
                            style={{ marginTop:8, display:'flex', alignItems:'center', gap:6, fontSize:13, color:'#1E3A8A', fontWeight:600, background:'none', border:'none', cursor:'pointer', padding:'4px 0' }}>
                            <Plus size={15}/> 이름 추가
                        </button>
                    </div>

                    {/* 건의사항 */}
                    <div>
                        <label style={{ fontSize:13, fontWeight:600, color:'#374151', display:'block', marginBottom:6 }}>
                            건의사항 <span style={{ color:'#9ca3af', fontWeight:400 }}>(선택)</span>
                        </label>
                        <textarea value={suggestion} onChange={e=>setSuggestion(e.target.value)}
                            placeholder="건의사항이 있으면 남겨주세요" rows={2} className={inputCls}/>
                    </div>

                    {/* 대표자 서명 */}
                    <div>
                        <label style={{ fontSize:13, fontWeight:600, color:'#374151', display:'block', marginBottom:8 }}>
                            대표자 서명
                        </label>
                        {signature ? (
                            <div style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 14px', border:'1px solid #d1fae5', borderRadius:10, background:'#f0fdf4' }}>
                                <img src={signature} style={{ height:48, border:'0.5px solid #e5e7eb', borderRadius:6, background:'#fff' }}/>
                                <div style={{ flex:1 }}>
                                    <p style={{ fontSize:13, fontWeight:600, color:'#166534', margin:0 }}>서명 완료</p>
                                    <p style={{ fontSize:11, color:'#4ade80', margin:0 }}>활동일지에 포함됩니다</p>
                                </div>
                                <button type="button" onClick={() => { setSignature(''); setShowSigPad(true); }}
                                    style={{ fontSize:12, color:'#6b7280', border:'1px solid #e5e7eb', borderRadius:6, padding:'4px 10px', background:'#fff', cursor:'pointer' }}>
                                    다시 서명
                                </button>
                            </div>
                        ) : showSigPad ? (
                            <SignaturePad onSave={(url) => { setSignature(url); setShowSigPad(false); }}/>
                        ) : (
                            <button type="button" onClick={() => setShowSigPad(true)}
                                style={{ width:'100%', padding:'12px', border:'1.5px dashed #93c5fd', borderRadius:10, background:'#eff6ff', color:'#1E3A8A', fontSize:13, fontWeight:600, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
                                <PenLine size={16}/> 대표자 서명하기
                            </button>
                        )}
                    </div>

                    {/* 미리 인쇄 버튼 (학생에게는 보이지 않음, 관리자 기능 도입 예정) */}

                </div>

                {/* 하단 버튼 */}
                <div style={{ display:'flex', gap:12, padding:20, borderTop:'0.5px solid #e5e7eb', background:'#f9fafb', borderRadius:'0 0 16px 16px', position:'sticky', bottom:0 }}>
                    <button onClick={onClose}
                        style={{ flex:1, padding:'12px', border:'2px solid #e5e7eb', borderRadius:12, fontWeight:700, color:'#6b7280', background:'#fff', cursor:'pointer', fontSize:14 }}>
                        취소
                    </button>
                    <button onClick={handleSubmit} disabled={isLoading}
                        style={{ flex:1, padding:'12px', border:'none', borderRadius:12, fontWeight:700, color:'#fff', background: isLoading ? '#e5e7eb' : '#22C55E', cursor: isLoading ? 'not-allowed' : 'pointer', fontSize:14, boxShadow:'0 4px 12px rgba(34,197,94,0.3)' }}>
                        {isLoading ? '처리중...' : '예약 신청 완료'}
                    </button>
                </div>
            </div>
        </div>
    );
}
